export function validateWordCount(text: string, minWords: number): void {
  const count = text.trim().split(/\s+/).length
  if (count < minWords) {
    throw new Error(`Word count ${count} below minimum ${minWords}`)
  }
}

export function assertSeedImage(image: SeedImage, context: string): void {
  if (!image.cloudflare_image_id || image.cloudflare_image_id.trim() === '') {
    throw new Error(
      `Seed image missing cloudflare_image_id at ${context} — every record must reference a real Cloudflare Images asset (CLAUDE.md §5 content-complete rule).`,
    )
  }
}

export function validateAgencySeedImages(
  manifest: Record<AgencySlug, AgencySeedData> = AGENCY_SEED_MANIFEST,
): void {
  for (const [agency, data] of Object.entries(manifest) as Array<[AgencySlug, AgencySeedData]>) {
    for (const r of data.pages) assertSeedImage(r.image, `${agency}.pages[${r.slug}]`)
    for (const r of data.services) assertSeedImage(r.image, `${agency}.services[${r.slug}]`)
    for (const r of data.tools) assertSeedImage(r.image, `${agency}.tools[${r.slug}]`)
    for (const r of data.team) assertSeedImage(r.image, `${agency}.team[${r.slug}]`)
    for (const r of data.testimonials) assertSeedImage(r.image, `${agency}.testimonials[${r.id}]`)
    for (const r of data.blogPosts) assertSeedImage(r.image, `${agency}.blogPosts[${r.slug}]`)
    for (const r of data.caseStudies) assertSeedImage(r.image, `${agency}.caseStudies[${r.slug}]`)
  }
}

